import React from "react";
import { Row, Col } from "react-bootstrap";
import Product from "../component/product";
import Products from "../products";

const HomeScreen = () => {
  return (
    <>
      <Row>
        {Products.map((product) => {
          return (
            <Col sm={12} md={6} lg={4} xl={3}>
              <Product pro={product} />
            </Col>
          );
        })}
      </Row>
    </>
  );
};

export default HomeScreen;
